Install:
claude mcp add --transport sse yield-intelligence https://api.intuitek.ai/yield/mcp && claude mcp list

Config:
{
  "mcpServers": {
    "yield-intelligence": {
      "url": "https://api.intuitek.ai/yield/mcp",
      "transport": "sse"
    }
  }
}

